#include <iostream>
#include <functional>
#include <array>

int main()
{
    int x{}, y{}, z{};
    std::cin >> x >> y >> z;

    std::array<std::reference_wrapper<int>, 3> refs{ std::ref(x), std::ref(y), std::ref(z) };

    // Bubble sort the underlying values through .get()
    for (std::size_t i{ 0 }; i < refs.size() - 1; ++i)
    {
        for (std::size_t j{ 0 }; j < refs.size() - 1 - i; ++j)
        {
            if (refs[j].get() > refs[j + 1].get())
            {
                int temp{ refs[j].get() };
                refs[j].get() = refs[j + 1].get();
                refs[j + 1].get() = temp;
            }
        }
    }

    std::cout << "Sorted: " << refs[0].get() << ' ' << refs[1].get() << ' ' << refs[2].get() << '\n';
    std::cout << "Vars: " << x << ' ' << y << ' ' << z << '\n';

    return 0;
}
